('spanish:9-1-my-town-home-and-local-area:misc:f82b879a', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Mi pueblo es más tranquilo la ciudad.</p><p><strong>✅ The correct idea:</strong> Mi pueblo es más tranquilo que la ciudad.</p>", "question": "What word is missing from the comparison?", "options": ["que (than)", "muy (very)", "con (with)", "de (of)"]}'::jsonb, '{"answer": 0, "explain": "Comparatives need más/menos + adjective + QUE: más tranquilo que la ciudad."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:misc:e3285aee', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Vivo en un piso pequeño de niño.</p><p><strong>✅ The correct idea:</strong> De niño, vivía en un piso pequeño.</p>", "question": "Why must this be in the imperfect tense (vivía)?", "options": ["‘de niño’ signals a past, no-longer-true situation", "‘piso’ is secretly a feminine noun", "the sentence is actually written as a direct command", "‘pequeño’ must agree with the verb ‘vivo’"]}'::jsonb, '{"answer": 0, "explain": "‘de niño’ (as a child) signals a past habitual state → imperfect: vivía, not the present vivo."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tips:1c779933', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Listening: hay vs no hay vs se puede", "reading": "These three sound similar but mean different things: hay (there is), no hay (there isn’t), se puede (you can). Listen carefully for a ‘no’ before hay or puede, and for whether puede replaces hay entirely.", "question": "You hear ‘no se puede aparcar aquí’. What does it mean?", "options": ["you cannot park here", "there is a car park just here", "you must park here now", "there used to be no parking here"]}'::jsonb, '{"answer": 0, "explain": "no se puede + infinitive = you cannot… — listen for the negative before se puede."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tips:c935b5dd', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 2 — Speaking: photo card on your local area", "reading": "Describe what there is (hay), add an opinion adjective (tranquilo / animado / ruidoso) and a preposition of place (al lado de / cerca de). Examiners reward range, not just accuracy.", "question": "Which answer shows the most range for a photo of a town centre?", "options": ["Hay muchas tiendas y el ayuntamiento está al lado de la estación", "Hay tiendas en el centro", "Hay una tienda pequeña", "Hay tiendas, hay tiendas y hay muchas tiendas en el centro de mi pueblo"]}'::jsonb, '{"answer": 0, "explain": "It combines hay, a specific place noun and a preposition of place. Option D is longer but just repeats ‘hay tiendas’ — length without any real range."}'::jsonb),
('spanish:9-1-my-town-home-and-local-area:tips:e94227f0', 'spanish', 'spanish:9-1-my-town-home-and-local-area', '9.1 My Town, Home and Local Area', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Paper 4 — Writing & translation with Higher structures", "reading": "For the top band, combine a comparative (más… que) with the imperfect (antes vivía…) and a preposition of place: ‘Mi barrio es más animado que el pueblo donde vivía antes.’", "question": "Which sentence reaches the top band?", "options": ["Mi barrio es más animado que el pueblo donde vivía antes", "Mi barrio es animado", "Mi barrio es animado y animado y animado y muy animado también", "Mi barrio bueno"]}'::jsonb, '{"answer": 0, "explain": "It uses a comparative plus the imperfect (vivía) — range and complexity, not just a long string of repeated simple words."}'::jsonb),
